    items: enrichedItems,
  });
});

// POST /orders - create a new order
router.post("/orders", (req, res) => {
  const input = req.body as CreateOrderInput;

  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    res.status(400).json({ error: "userId and items are required" });
    return;
  }

  if (input.items.length === 0) {
    res.status(400).json({ error: "Order must have at least one item" });
    return;
  }

  // Validate items and calculate totals
  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      res.status(400).json({ error: `Product ${item.productId} not found` });
      return;
    }

    if (item.quantity <= 0) {
      res.status(400).json({ error: "Quantity must be positive" });
      return;
    }

    if (product.stock < item.quantity) {
      res
        .status(400)
        .json({ error: `Insufficient stock for ${product.name}` });
      return;
    }

    // Deduct stock
    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending" as const,
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  res.status(201).json(order);
});

// PATCH /orders/:id/status - update order status
router.patch("/orders/:id/status", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const order = orders.find((o) => o.id === id);

  if (!order) {
    res.status(404).json({ error: "Order not found" });
    return;
  }

  const { status } = req.body as { status: string };
  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];

  if (!validStatuses.includes(status)) {
    res.status(400).json({ error: `Invalid status. Must be one of: ${validStatuses.join(", ")}` });
    return;
  }

  // Validate status transitions
  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    res.status(400).json({
      error: `Cannot transition from ${order.status} to ${status}`,
    });
    return;
  }

  order.status = status as typeof order.status;

  res.json(order);
});

export { router as orderRouter };
```

**Business Logic to Extract:**
- **Filtering logic:** Filter orders by userId, filter by status
- **Calculations:**
  - Total revenue aggregation: `sum(order.total)`
  - Rounding to 2 decimal places
  - Order total calculation: `sum(product.price * item.quantity)`
- **Data enrichment:** Join order items with product names (LEFT JOIN-like behavior with fallback to "Unknown")
- **Data validation:**
  - Input validation: userId and items required
  - Items array must not be empty
  - Product existence check
  - Quantity must be positive
  - Stock availability check
  - Type checking for query/body parameters
- **Business rules:**
  - Order status state machine (pending → confirmed → shipped → delivered)
  - Valid status transitions enforcement
  - Stock deduction on order creation (inventory management)
- **ID generation:** Call to `getNextOrderId()` function

**HTTP Concerns:**
- Status codes: 201 (created), 400 (bad request), 404 (not found), 200 (implicit success)
- Query parameters: `userId`, `status`
- URL parameters: `:id`
- Request body parsing: JSON with `items` array and `status` field
- Response structure with wrapped data (`{ orders, summary }`)
- Timestamp generation: `new Date().toISOString()`

**Direct Dependencies:**
- `express` (Router)
- `../data.js` (orders, products arrays, getNextOrderId function)
- `../types.js` (CreateOrderInput, OrderItem TypeScript types)

---

### Supporting Files

**Data Layer:** `/src/data.ts`
- In-memory arrays: `products`, `orders`
- ID generation function: `getNextOrderId()`
- No persistence layer, no database abstractions

**Types:** `/src/types.ts`
- Product, Order, OrderItem, CreateOrderInput interfaces
- No validation schemas (validation is inline in route handlers)

**App Entry:** `/src/app.ts`
- Basic Express setup with JSON middleware
- Route registration with no middleware chains

---

### Summary of Business Logic by Category

| Category | Details |
|----------|---------|
| **Filtering** | Category, price range (products); userId, status (orders) |
| **Calculations** | Inventory value, average price, revenue, order totals, decimal rounding |
| **Validations** | Type checking, numeric bounds, stock checks, required fields, status validity |
| **Business Rules** | Low stock detection, order status state machine, stock deduction on purchase |
| **Data Access** | Direct array searching (`.find()`), filtering (`.filter()`), mutation (direct assignment) |
| **Data Enrichment** | Joining products to orders, computed properties (isLowStock, inventoryValue) |
| **ID Generation** | Incrementing counter for order IDs |

---

### Extraction Opportunities

**Business logic candidates for services/repositories:**
1. **ProductService**: listing, filtering, stock management, calculations
2. **OrderService**: order creation, status transitions, enrichment
3. **InventoryService**: stock tracking, low stock detection
4. **ValidationService**: common validation rules
5. **CalculationService**: rounding, revenue/inventory value calculations
6. **Data Repository/DAO**: abstraction over products/orders arrays

**Current Problems:**
- Business logic tightly coupled to HTTP layer
- Difficult to test business rules in isolation
- Validation scattered across multiple handlers
- Code duplication (e.g., rounding logic, filtering patterns)
- No transaction semantics for multi-step operations (e.g., stock deduction + order creation)
- Direct data mutation without abstraction

