  const { userId, status } = req.query;
  const uid = typeof userId === "string" ? parseInt(userId, 10) : NaN;
  res.json(listOrders({
    userId: isNaN(uid) ? undefined : uid,
    status: typeof status === "string" ? status : undefined,
  }));
});

// GET /orders/:id
router.get("/orders/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  try {
    res.json(getOrder(id));
  } catch (err) {
    if (err instanceof AppError) res.status(err.statusCode).json({ error: err.message });
    else throw err;
  }
});

// POST /orders
router.post("/orders", (req, res) => {
  const input = req.body as CreateOrderInput;
  if (!input.userId || !input.items || !Array.isArray(input.items)) {  // structural HTTP guard
    res.status(400).json({ error: "userId and items are required" });
    return;
  }
