import { orders, products, getNextOrderId } from "../data.js";
import { AppError } from "../errors.js";
import type { CreateOrderInput, OrderItem } from "../types.js";

export function listOrders(filters: { userId?: number; status?: string }) {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }

  if (filters.status !== undefined) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrder(id: number) {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    throw new AppError(404, "Order not found");
  }

  const enrichedItems = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return { ...order, items: enrichedItems };
}

export function createOrder(input: CreateOrderInput) {
  if (input.items.length === 0) {
    throw new AppError(400, "Order must have at least one item");
  }

  // Pass 1: validate all items before any mutations
  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      throw new AppError(400, `Product ${item.productId} not found`);
    }
    if (item.quantity <= 0) {
      throw new AppError(400, "Quantity must be positive");
    }
    if (product.stock < item.quantity) {
      throw new AppError(400, `Insufficient stock for ${product.name}`);
    }
  }

  // Pass 2: deduct stock and build order items
  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId)!;
    product.stock -= item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += product.price * item.quantity;
  }

  const order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending" as const,
    createdAt: new Date().toISOString(),
  };

  orders.push(order);
  return order;
}

export function updateOrderStatus(id: number, status: string) {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    throw new AppError(404, "Order not found");
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];
  if (!validStatuses.includes(status)) {
    throw new AppError(
      400,
      `Invalid status. Must be one of: ${validStatuses.join(", ")}`
    );
  }

  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    throw new AppError(
      400,
      `Cannot transition from ${order.status} to ${status}`
    );
  }

  order.status = status as typeof order.status;
  return order;
}

